class Solution:
    def increasingBST(self, root):
        vals = []
        def inorder(node):
            if not node:
                return
            inorder(node.left)
            vals.append(node.val)
            inorder(node.right)
        inorder(root)
        dummy = TreeNode(0)
        cur = dummy
        for v in vals:
            cur.right = TreeNode(v)
            cur = cur.right
        return dummy.right

