var increasingBST = function(root) {
    const vals = [];
    function inorder(node) {
        if (!node) return;
        inorder(node.left);
        vals.push(node.val);
        inorder(node.right);
    }
    inorder(root);
    const dummy = new TreeNode(0);
    let cur = dummy;
    for (const v of vals) {
        cur.right = new TreeNode(v);
        cur = cur.right;
    }
    return dummy.right;
};
